            let mut wr: [u8; 1] = [0];
            let mut ex: [u8; 1] = [0];
            let rd_mut_ptr = (&raw mut rd_mut[0]) as u64;
            let wr_ptr = (&raw mut wr[0]) as u64;
            let ex_ptr = (&raw mut ex[0]) as u64;
