        if v != -i64::from(errno::EOPNOTSUPP) {
            serial_println!(
                "[syscall/linux]   FAIL: landlock_restrict_self(high|LOG_SAME_EXEC_OFF) -> {} (expected -EOPNOTSUPP)",
                v
            );
            return Err(KernelError::InternalError);
        }

